// RiderRegister.js
import React, { useState } from "react";
import {
  Container, Paper, Typography, TextField, Button, Alert, Box, CircularProgress, Dialog, DialogTitle, DialogContent, DialogActions
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { signupRider, uploadRiderDocs } from "../services/api";

export default function RiderRegister() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ fullName: "", email: "", mobile: "" });
  const [documents, setDocuments] = useState([]);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [successPopup, setSuccessPopup] = useState(false);

  const validateFile = (file) => {
    if (!file) return false;
    const validTypes = ["image/jpeg", "image/png", "image/jpg"];
    const maxSize = 5 * 1024 * 1024;
    if (!validTypes.includes(file.type)) { setError("Only JPG/PNG allowed."); return false; }
    if (file.size > maxSize) { setError("File size < 5MB."); return false; }
    return true;
  };

  const handleChange = (e) => setFormData(prev => ({ ...prev, [e.target.name]: e.target.value }));

  const handleFileChange = (e) => {
    setError("");
    const files = Array.from(e.target.files);
    if (documents.length + files.length > 3) {
      setError("Maximum 3 documents allowed.");
      return;
    }
    const validFiles = files.filter(validateFile);
    setDocuments(prev => [...prev, ...validFiles]);
  };

  const removeFile = (index) => setDocuments(prev => prev.filter((_, i) => i !== index));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(""); setLoading(true);

    if (!documents.length) { setError("Upload at least 1 document."); setLoading(false); return; }

    try {
      const res = await signupRider({ ...formData, role: "rider" });
      const riderId = res.data?.data?.id || res.data?.data?._id;
      if (!riderId) throw new Error("No Rider ID returned.");

      const formDataUpload = new FormData();
      documents.forEach(file => formDataUpload.append("documents", file));
      await uploadRiderDocs(riderId, formDataUpload);

      setSuccessPopup(true);
      setTimeout(() => navigate("/rider-login"), 3000);
    } catch (err) {
      setError(err.response?.data?.message || err.message || "Server error.");
    } finally { setLoading(false); }
  };

  return (
    <Container maxWidth="xs">
      <Paper sx={{ mt: 6, p: 4, borderRadius: 3, textAlign: "center", boxShadow: 5 }}>
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>Rider Signup</Typography>
        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        <form onSubmit={handleSubmit}>
          <TextField fullWidth label="Full Name" name="fullName" value={formData.fullName} onChange={handleChange} margin="normal" required />
          <TextField fullWidth type="email" label="Email" name="email" value={formData.email} onChange={handleChange} margin="normal" required />
          <TextField fullWidth type="tel" label="Mobile Number" name="mobile" value={formData.mobile} onChange={handleChange} margin="normal" inputProps={{ maxLength: 10 }} required />
          <Typography variant="h6" sx={{ mt: 3, mb: 1 }}>Upload Documents (max 3)</Typography>
          <Box sx={{ display: "flex", flexDirection: "column", gap: 1, textAlign: "left" }}>
            <input type="file" multiple onChange={handleFileChange} />
            {documents.length > 0 && (
              <ul>
                {documents.map((file, idx) => (
                  <li key={idx}>{file.name} <Button size="small" onClick={() => removeFile(idx)}>Remove</Button></li>
                ))}
              </ul>
            )}
          </Box>
          <Button type="submit" fullWidth variant="contained" sx={{ mt: 3, bgcolor: "black", fontWeight: "bold" }} disabled={loading}>
            {loading ? <CircularProgress size={24} color="inherit" /> : "Sign Up"}
          </Button>
        </form>
      </Paper>

      <Dialog open={successPopup}>
        <DialogTitle>Success</DialogTitle>
        <DialogContent>
          Registered successfully! Please wait for admin approval.
        </DialogContent>
        <DialogActions>
          <Button onClick={() => navigate("/rider-login")}>Go to Login</Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
}
